    # Look for 'in the categories of', 'in the category of', 'in the categories', 'in the category', 'offers a range of services in', 'offers a range of services including'
    patterns = [r'in the categories? of ([^.]+)\.', r'offers a range of services in ([^.]+)\.', r'offers a range of services including ([^.]+)\.', r'offers a range of services in ([^.]+)$', r'offers[^.]* in ([^.]+)\.', r'including ([^.]+)\.', r'category of ["\']?([^"\']+)["\']?']
    match = None
    for pat in patterns:
