    final = []
    for t in tokens:
        parts = re.split(r'\s+and\s+|\s*&\s*', t)
        for p in parts:
            p = p.strip()
            # filter short tokens likely to be state codes or location
            if len(p) <= 2:
                continue
            # filter tokens that are clearly addresses or city/state
            if re.search(r'\d', p):
